module multiplexer_1bit_4to1 (
    input [1:0] sel,
    input in0,
    input in1,
    input in2,
    input in3,
    output out
);

    wire mux_output = (sel == 2'b00) ? in0 :
                 (sel == 2'b01) ? in1 :
                 (sel == 2'b10) ? in2 : in3;
    assign out = mux_output;

endmodule
